const texto = $input.first().json.texto;

// Divide por seções (---)
const secoes = texto.split('---').filter(s => s.trim());

// Cria chunks com metadata
const chunks = secoes.map((secao, index) => {
  // Tenta extrair o título da seção (primeira linha com #)
  const linhas = secao.trim().split('\n');
  const tituloMatch = linhas.find(l => l.startsWith('#'));
  const titulo = tituloMatch ? tituloMatch.replace(/#/g, '').trim() : `Seção ${index + 1}`;

  return {
    content: secao.trim(),
    metadata: {
      source: 'base_conhecimento_clinica_vida_saude',
      section: titulo,
      index: index,
      created_at: new Date().toISOString()
    }
  };
});

return chunks.map(chunk => ({ json: chunk }));
